export const measurePerformance = <T>(name: string, fn: () => T): T => {
  const start = performance.now();
  const result = fn();
  const end = performance.now();
  console.log(`#DEBUG: ${name} - ${(end - start).toFixed(2)}ms`);
  return result;
};

// #DEBUG: 벤치마크 함수
export const runGigachadBenchmark = () => {
  console.log('#DEBUG: Running GigaChad Benchmark...');
  
  const iterations = 1000000;
  const start = performance.now();
  
  // 스타일 접근 테스트
  for (let i = 0; i < iterations; i++) {
    const style = GIGACHAD_COMMON.cardBase;
    const button = GIGACHAD_COMMON.btnPrimary;
    const flex = GIGACHAD_COMMON.flexCenter;
  }
  
  const end = performance.now();
  const duration = end - start;
  const opsPerSec = Math.floor(iterations / (duration / 1000));
  
  return {
    iterations,
    duration: duration.toFixed(2) + 'ms',
    opsPerSec: opsPerSec.toLocaleString(),
    score: opsPerSec > 100000000 ? 'GIGACHAD_LEVEL' : 'NEEDS_MORE_POWER',
    memoryUsage: getMemoryUsage()
  };
};

// #DEBUG: 메모리 사용량 측정
export const getMemoryUsage = () => {
  if (typeof window !== 'undefined' && window.performance && (window.performance as any).memory) {
    const memory = (window.performance as any).memory;
    return {
      used: Math.round(memory.usedJSHeapSize / 1024 / 1024) + 'MB',
      total: Math.round(memory.totalJSHeapSize / 1024 / 1024) + 'MB',
      limit: Math.round(memory.jsHeapSizeLimit / 1024 / 1024) + 'MB'
    };
  }
  return { used: 'N/A', total: 'N/A', limit: 'N/A' };
};

// #DEBUG: 스타일 조합 헬퍼
export const combineStyles = (...styles: string[]): string => {
  return styles.filter(Boolean).join(' ');
};

// #DEBUG: 조건부 스타일 헬퍼
export const conditionalStyle = (condition: boolean, trueStyle: string, falseStyle = ''): string => {
  return condition ? trueStyle : falseStyle;
};

// #DEBUG: 버튼 스타일 빌더
export const buildButtonStyle = (variant: 'primary' | 'secondary' | 'danger' | 'ghost' = 'primary', size: 'sm' | 'md' | 'lg' = 'md'): string => {
  const variants = {
    primary: GIGACHAD_COMMON.btnPrimary,
    secondary: GIGACHAD_COMMON.btnSecondary,
    danger: GIGACHAD_COMMON.btnDanger,
    ghost: GIGACHAD_COMMON.btnGhost
  };
  
  const sizes = {
    sm: 'px-2 py-1 text-sm',
    md: 'px-4 py-2',
    lg: 'px-6 py-3 text-lg'
  };
  
  return combineStyles(variants[variant], sizes[size]);
};

